// SW Rsrc, Offset(Rbase) - Store Rsrc to memory at address (Rbase + Offset)

BEGIN
 // Cycle 1: Compute effective address
 MAR ← Rbase + SignExtend(Offset) // Address computation

 // Cycle 2: Load data into MDR
 MDR ← Rsrc // Data to be stored

 // Cycle 3: Write to memory
 WR ← 1 // Enable write
 WAIT UNTIL MFC = 1 // Wait for memory completion
 M[MAR] ← MDR // Transfer data to memory
 WR ← 0 // De-assert write signal

 // Update PC (increment or branch)
 PC ← PC + 4
END
